public static void main(Args _args)
{
    FormRun             formRun;
    FormDataSource      formDataSource;
    ETG_BOLCarrierTable carrierTable;
    SalesIdOrig         currSalesId;

    // Get the form run instance
    formRun =   _args.caller() as FormRun;

    if (!formRun)
    {
        throw error("Form is not open.");
    }

    formDataSource = formRun.dataSource(formDataSourceStr(ETG_BOLContainerForm, BOLContainerTable));

    if (!formDataSource)
    {
        throw error("Data source not found.");
    }

    if(formRun is FormRun && formHasMethod(formRun, identifierStr("getSalesId")))
    {
        currSalesId = formRun.getSalesId();
    }

    ETG_ImportDataExcel::getInsertDataSalesPackingSlip(ETG_ImportDataExcel::getImportExcel(), currSalesId);

    formDataSource.executeQuery();
}
